 10→
 11→const mockSpawn = vi.mocked(childProcess.spawn);
 12→const mockExecSync = vi.mocked(childProcess.execSync);
 13→
 14→/** Create a mock child process with EventEmitter-like behavior */
 15→function createMockProcess(options?: {
 16→  exitCode?: number | null;
 17→  signal?: string | null;
 18→  stdout?: string[];
 19→  stderr?: string[];
 20→  error?: NodeJS.ErrnoException;
 21→}) {
 22→  const stdoutListeners: Array<(data: Buffer) => void> = [];
 23→  const stderrListeners: Array<(data: Buffer) => void> = [];
 24→  const processListeners: Record<
 25→    string,
 26→    Array<(...args: unknown[]) => void>
 27→  > = {};
 28→
 29→  const proc = {
 30→    stdout: {
 31→      on: vi.fn((event: string, cb: (data: Buffer) => void) => {
 32→        if (event === "data") stdoutListeners.push(cb);
 33→      }),
 34→    },
 35→    stderr: {
 36→      on: vi.fn((event: string, cb: (data: Buffer) => void) => {
 37→        if (event === "data") stderrListeners.push(cb);
 38→      }),
 39→    },
 40→    on: vi.fn((event: string, cb: (...args: unknown[]) => void) => {
 41→      if (!processListeners[event]) processListeners[event] = [];
 42→      processListeners[event].push(cb);
 43→    }),
 44→    kill: vi.fn(),
 45→  };
 46→
 47→  // Schedule emissions in microtask queue
 48→  setTimeout(() => {
 49→    // Emit stdout chunks
 50→    if (options?.stdout) {
 51→      for (const chunk of options.stdout) {
 52→        stdoutListeners.forEach((cb) => cb(Buffer.from(chunk)));
 53→      }
 54→    }
 55→    // Emit stderr chunks
 56→    if (options?.stderr) {
 57→      for (const chunk of options.stderr) {
 58→        stderrListeners.forEach((cb) => cb(Buffer.from(chunk)));
 59→      }
 60→    }
 61→    // Emit error or close
 62→    if (options?.error) {
 63→      processListeners["error"]?.forEach((cb) => cb(options.error));
 64→    } else {
 65→      processListeners["close"]?.forEach((cb) =>
 66→        cb(options?.exitCode ?? 0, options?.signal ?? null),
 67→      );
 68→    }
 69→  }, 0);
 70→
 71→  return proc;
 72→}
