306→/**
307→ * Execute a phase with automatic retry for cold-start failures and MCP fallback.
308→ *
309→ * Retry strategy:
310→ * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
311→ * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
312→ *    can fail on first run due to cold-cache issues)
313→ *
314→ * The MCP fallback is safe because MCP servers are optional enhancements, not required
315→ * for core functionality.
316→ */
317→/**
318→ * @internal Exported for testing only
319→ */
320→export async function executePhaseWithRetry(
321→  issueNumber: number,
322→  phase: Phase,
323→  config: ExecutionConfig,
324→  sessionId?: string,
325→  worktreePath?: string,
326→  shutdownManager?: ShutdownManager,
327→  spinner?: PhaseSpinner,
328→  /** @internal Injected for testing — defaults to module-level executePhase */
329→  executePhaseFn: typeof executePhase = executePhase,
330→): Promise<PhaseResult & { sessionId?: string }> {
331→  // Skip retry logic if explicitly disabled
332→  if (config.retry === false) {
333→    return executePhaseFn(
334→      issueNumber,
335→      phase,
336→      config,
337→      sessionId,
338→      worktreePath,
339→      shutdownManager,
340→      spinner,
341→    );
342→  }
343→
344→  let lastResult: PhaseResult & { sessionId?: string };
345→
346→  // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
347→  for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
348→    lastResult = await executePhaseFn(
349→      issueNumber,
350→      phase,
351→      config,
352→      sessionId,
353→      worktreePath,
354→      shutdownManager,
355→      spinner,
356→    );
357→
358→    const duration = lastResult.durationSeconds ?? 0;
