  2→ * AiderDriver — AgentDriver implementation wrapping the Aider CLI.
  3→ *
  4→ * Shells out to `aider --yes --no-auto-commits --message "<prompt>"`
  5→ * for fully non-interactive phase execution. Sequant manages git,
  6→ * not Aider.
  7→ */
  8→
  9→import { spawn } from "child_process";
 10→import { execSync } from "child_process";
 11→import type {
 12→  AgentDriver,
 13→  AgentExecutionConfig,
 14→  AgentPhaseResult,
 15→} from "./agent-driver.js";
 16→import type { AiderSettings } from "../../settings.js";
 17→
 18→export class AiderDriver implements AgentDriver {
 19→  name = "aider";
 20→
 21→  private settings?: AiderSettings;
 22→
 23→  constructor(settings?: AiderSettings) {
 24→    this.settings = settings;
 25→  }
 26→
 27→  async executePhase(
 28→    prompt: string,
 29→    config: AgentExecutionConfig,
 30→  ): Promise<AgentPhaseResult> {
 31→    const args = this.buildArgs(prompt);
 32→
 33→    return new Promise<AgentPhaseResult>((resolve) => {
 34→      let capturedOutput = "";
 35→      let capturedStderr = "";
 36→
 37→      const proc = spawn("aider", args, {
 38→        cwd: config.cwd,
 39→        env: { ...process.env, ...config.env },
 40→        stdio: ["ignore", "pipe", "pipe"],
 41→      });
 42→
 43→      // Set up timeout
 44→      const timeoutId = setTimeout(() => {
 45→        proc.kill("SIGTERM");
 46→      }, config.phaseTimeout * 1000);
 47→
 48→      // Wire external abort signal
 49→      if (config.abortSignal) {
 50→        const onAbort = () => {
 51→          proc.kill("SIGTERM");
 52→        };
 53→        config.abortSignal.addEventListener("abort", onAbort);
 54→        proc.on("close", () => {
 55→          config.abortSignal?.removeEventListener("abort", onAbort);
 56→        });
 57→      }
 58→
 59→      proc.stdout.on("data", (data: Buffer) => {
 60→        const text = data.toString();
 61→        capturedOutput += text;
 62→        if (config.verbose) {
 63→          config.onOutput?.(text);
 64→        }
 65→      });
 66→
 67→      proc.stderr.on("data", (data: Buffer) => {
 68→        const text = data.toString();
 69→        capturedStderr += text;
 70→        config.onStderr?.(text);
 71→      });
 72→
 73→      proc.on("error", (err: NodeJS.ErrnoException) => {
 74→        clearTimeout(timeoutId);
 75→        if (err.code === "ENOENT") {
 76→          resolve({
 77→            success: false,
 78→            output: capturedOutput,
 79→            error:
 80→              "Aider CLI not found. Install it with: pip install aider-chat",
 81→          });
 82→        } else {
 83→          resolve({
 84→            success: false,
 85→            output: capturedOutput,
 86→            error: `Failed to start aider: ${err.message}`,
 87→          });
 88→        }
 89→      });
 90→
 91→      proc.on("close", (code: number | null, signal: string | null) => {
 92→        clearTimeout(timeoutId);
 93→
 94→        if (signal) {
 95→          const isTimeout = signal === "SIGTERM";
 96→          resolve({
 97→            success: false,
 98→            output: capturedOutput,
 99→            error: isTimeout
100→              ? `Timeout after ${config.phaseTimeout}s`
101→              : `Process killed by signal: ${signal}`,
102→          });
103→          return;
104→        }
105→
106→        if (code === 0) {
107→          resolve({
108→            success: true,
109→            output: capturedOutput,
110→          });
111→        } else {
112→          const stderrSuffix = capturedStderr
113→            ? `\nStderr: ${capturedStderr.slice(0, 500)}`
114→            : "";
115→          resolve({
116→            success: false,
117→            output: capturedOutput,
118→            error: `Aider exited with code ${code}${stderrSuffix}`,
119→          });
120→        }
121→      });
122→    });
123→  }
124→
125→  async isAvailable(): Promise<boolean> {
126→    try {
127→      execSync("which aider", { stdio: "pipe" });
128→      return true;
129→    } catch {
130→      return false;
131→    }
132→  }
133→
134→  /** Build the CLI argument list for aider. */
135→  private buildArgs(prompt: string): string[] {
136→    const args = [
137→      "--yes",
138→      "--no-auto-commits",
139→      "--no-pretty",
140→      "--message",
141→      prompt,
142→    ];
143→
144→    if (this.settings?.model) {
145→      args.push("--model", this.settings.model);
146→    }
147→
148→    if (this.settings?.editFormat) {
149→      args.push("--edit-format", this.settings.editFormat);
150→    }
151→
152→    if (this.settings?.extraArgs) {
153→      args.push(...this.settings.extraArgs);
154→    }
155→
156→    return args;
157→  }
158→}
