 14→/** Create a mock child process that resolves immediately */
 15→function createQuickMockProcess(
 16→  exitCode: number,
 17→  stdout: string[] = [],
 18→  stderr: string[] = [],
 19→) {
 20→  const stdoutListeners: Array<(data: Buffer) => void> = [];
 21→  const stderrListeners: Array<(data: Buffer) => void> = [];
 22→  const processListeners: Record<
 23→    string,
 24→    Array<(...args: unknown[]) => void>
 25→  > = {};
 26→
 27→  const proc = {
 28→    stdout: {
 29→      on: vi.fn((_event: string, cb: (data: Buffer) => void) => {
 30→        stdoutListeners.push(cb);
 31→      }),
 32→    },
 33→    stderr: {
 34→      on: vi.fn((_event: string, cb: (data: Buffer) => void) => {
 35→        stderrListeners.push(cb);
 36→      }),
 37→    },
 38→    on: vi.fn((event: string, cb: (...args: unknown[]) => void) => {
 39→      if (!processListeners[event]) processListeners[event] = [];
 40→      processListeners[event].push(cb);
 41→    }),
 42→    kill: vi.fn(),
 43→  };
 44→
 45→  setTimeout(() => {
 46→    for (const chunk of stdout) {
 47→      stdoutListeners.forEach((cb) => cb(Buffer.from(chunk)));
 48→    }
 49→    for (const chunk of stderr) {
 50→      stderrListeners.forEach((cb) => cb(Buffer.from(chunk)));
 51→    }
 52→    processListeners["close"]?.forEach((cb) => cb(exitCode, null));
 53→  }, 0);
 54→
 55→  return proc;
 56→}
