280→/**
281→ * Validate aider-specific settings.
282→ * Throws on invalid types to catch config errors at load time.
283→ */
284→export function validateAiderSettings(
285→  aider: unknown,
286→): AiderSettings | undefined {
287→  if (aider == null) return undefined;
288→  if (typeof aider !== "object" || Array.isArray(aider)) {
289→    throw new Error("settings.run.aider must be an object");
290→  }
291→  const obj = aider as Record<string, unknown>;
292→  if (obj.model !== undefined && typeof obj.model !== "string") {
293→    throw new Error("settings.run.aider.model must be a string");
294→  }
295→  if (obj.editFormat !== undefined && typeof obj.editFormat !== "string") {
296→    throw new Error("settings.run.aider.editFormat must be a string");
297→  }
298→  if (obj.extraArgs !== undefined) {
299→    if (
300→      !Array.isArray(obj.extraArgs) ||
301→      !obj.extraArgs.every((a) => typeof a === "string")
302→    ) {
303→      throw new Error(
304→        "settings.run.aider.extraArgs must be an array of strings",
305→      );
306→    }
307→  }
308→  return obj as unknown as AiderSettings;
309→}
