311→/**
312→ * Get the current project settings
313→ *
314→ * Returns default settings if no settings file exists.
315→ */
316→export async function getSettings(): Promise<SequantSettings> {
317→  if (!(await fileExists(SETTINGS_PATH))) {
318→    return DEFAULT_SETTINGS;
319→  }
320→
321→  try {
322→    const content = await readFile(SETTINGS_PATH);
323→    const parsed = JSON.parse(content) as Partial<SequantSettings>;
324→
325→    // Validate aider settings if present
326→    const aiderSettings = validateAiderSettings(
327→      (parsed.run as Record<string, unknown> | undefined)?.aider,
328→    );
329→
330→    // Merge with defaults to ensure all fields exist
331→    return {
332→      version: parsed.version ?? DEFAULT_SETTINGS.version,
333→      run: {
334→        ...DEFAULT_SETTINGS.run,
335→        ...parsed.run,
336→        ...(aiderSettings !== undefined ? { aider: aiderSettings } : {}),
337→      },
338→      agents: {
